import React, { useState, useEffect, useRef } from 'react';
import './QuantumDashboard.css';

const QuantumDashboard = () => {
  const [activeTab, setActiveTab] = useState('quantum_dashboard');
  const [stats, setStats] = useState({
    total_requests: 12543,
    blocked_requests: 2341,
    sql_injections: 567,
    xss_attempts: 892,
    brute_force: 345,
    zero_day_attempts: 23,
    block_rate: 18.67,
    threat_actors: 156
  });
  
  const [logs, setLogs] = useState([]);
  const [attackers, setAttackers] = useState([]);
  const [aiConsole, setAiConsole] = useState([
    { type: 'ai', message: 'Quantum AI systems initialized. All quantum engines online.' },
    { type: 'ai', message: 'Quantum threat intelligence synchronized across dimensions.' },
    { type: 'ai', message: 'Neural networks optimized with quantum algorithms.' },
    { type: 'ai', message: 'Quantum deception technology deployed and active.' },
    { type: 'ai', message: 'Quantum shield operating at 99.9% efficiency.' },
    { type: 'ai', message: 'Ready for quantum cyber command operations.' }
  ]);

  const ws = useRef(null);
  const consoleRef = useRef(null);

  useEffect(() => {
    const connectWebSocket = () => {
      try {
        ws.current = new WebSocket('ws://localhost:8080/ws/quantum');
        
        ws.current.onopen = () => {
          console.log('🔌 Connected to Quantum WebSocket');
          addAIConsoleMessage('ai', 'WebSocket connected to Quantum AI backend');
        };
        
        ws.current.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            if (data.type === 'quantum_stats_update') {
              setStats(prevStats => ({ ...prevStats, ...data.data }));
            }
          } catch (error) {
            console.error('WebSocket message error:', error);
          }
        };
        
        ws.current.onclose = () => {
          console.log('WebSocket disconnected');
          addAIConsoleMessage('ai', 'WebSocket disconnected - attempting reconnect...');
          setTimeout(connectWebSocket, 3000);
        };
        
        ws.current.onerror = (error) => {
          console.error('WebSocket error:', error);
        };
      } catch (error) {
        console.error('WebSocket connection failed:', error);
      }
    };

    connectWebSocket();
    fetchInitialData();
    const demoInterval = setInterval(updateDemoData, 5000);

    return () => {
      if (ws.current) {
        ws.current.close();
      }
      clearInterval(demoInterval);
    };
  }, []);

  useEffect(() => {
    if (consoleRef.current) {
      consoleRef.current.scrollTop = consoleRef.current.scrollHeight;
    }
  }, [aiConsole]);

  const fetchInitialData = async () => {
    try {
      const baseURL = 'http://localhost:8080/api/quantum';
      
      const [statsRes, logsRes, attackersRes] = await Promise.all([
        fetch(`${baseURL}/stats`).catch(() => ({ ok: false })),
        fetch(`${baseURL}/logs`).catch(() => ({ ok: false })),
        fetch(`${baseURL}/attackers`).catch(() => ({ ok: false }))
      ]);

      if (statsRes.ok) {
        const statsData = await statsRes.json();
        setStats(prev => ({ ...prev, ...statsData }));
      } else {
        generateDemoData();
      }

      if (logsRes.ok) {
        const logsData = await logsRes.json();
        setLogs(logsData.slice(-20).reverse());
      }

      if (attackersRes.ok) {
        const attackersData = await attackersRes.json();
        setAttackers(attackersData.slice(0, 10));
      }

    } catch (error) {
      console.error('Error fetching initial data:', error);
      generateDemoData();
    }
  };

  const generateDemoData = () => {
    const demoLogs = [];
    const severities = ['LOW', 'MEDIUM', 'HIGH', 'CRITICAL'];
    const attackTypes = ['SQL_INJECTION', 'XSS', 'BRUTE_FORCE', 'SCANNING', 'BOT'];
    
    for (let i = 0; i < 20; i++) {
      demoLogs.push({
        id: i,
        Timestamp: new Date(Date.now() - Math.random() * 3600000).toISOString(),
        IP: `192.168.1.${Math.floor(Math.random() * 255)}`,
        Method: ['GET', 'POST', 'PUT', 'DELETE'][Math.floor(Math.random() * 4)],
        Path: ['/api/users', '/admin', '/login', '/wp-admin'][Math.floor(Math.random() * 4)],
        AttackType: attackTypes[Math.floor(Math.random() * attackTypes.length)],
        Severity: severities[Math.floor(Math.random() * severities.length)],
        ThreatScore: Math.random(),
        Description: 'Demo security event'
      });
    }
    setLogs(demoLogs);

    const demoAttackers = [];
    for (let i = 0; i < 10; i++) {
      demoAttackers.push({
        id: i,
        IP: `10.0.1.${Math.floor(Math.random() * 255)}`,
        ThreatLevel: severities[Math.floor(Math.random() * severities.length)],
        RiskScore: Math.random(),
        GeoLat: (Math.random() * 180) - 90,
        GeoLon: (Math.random() * 360) - 180,
        TotalAttacks: Math.floor(Math.random() * 1000),
        LastSeen: new Date().toISOString()
      });
    }
    setAttackers(demoAttackers);
  };

  const updateDemoData = () => {
    if (!ws.current || ws.current.readyState !== WebSocket.OPEN) {
      setStats(prev => ({
        ...prev,
        total_requests: prev.total_requests + Math.floor(Math.random() * 10),
        blocked_requests: prev.blocked_requests + Math.floor(Math.random() * 3),
        block_rate: Math.min(100, (prev.blocked_requests / prev.total_requests) * 100)
      }));
    }
  };

  const addAIConsoleMessage = (type, message) => {
    setAiConsole(prev => [...prev, { type, message }]);
  };

  const executeQuantumAICommand = (command) => {
    const commands = {
      'QUANTUM_DEFENSE': 'Activating quantum defense systems... Quantum entanglement established. Defense matrix optimized.',
      'AI_OPTIMIZATION': 'Optimizing AI algorithms... Quantum neural networks enhanced. Performance improved by 45%.',
      'THREAT_ANALYSIS': 'Initiating quantum threat analysis... Multidimensional scanning complete. No quantum threats detected.',
      'QUANTUM_SCAN': 'Executing quantum vulnerability scan... Scanning quantum space-time. All systems secure.',
      'NEURAL_ENHANCE': 'Enhancing neural networks... Quantum learning algorithms activated. AI intelligence boosted.',
      'SHIELD_BOOST': 'Boosting quantum shield... Shield strength increased to 99.99%. Multiversal protection active.'
    };

    if (commands[command]) {
      addAIConsoleMessage('user', command);
      setTimeout(() => {
        addAIConsoleMessage('ai', commands[command]);
      }, 500);
    }
  };

  const getThreatLevel = () => {
    const blockRate = stats.block_rate || 0;
    if (blockRate > 15) return { level: 'CRITICAL', class: 'critical' };
    if (blockRate > 8) return { level: 'HIGH', class: 'high' };
    if (blockRate > 3) return { level: 'MEDIUM', class: 'medium' };
    return { level: 'LOW', class: 'low' };
  };

  const threatLevel = getThreatLevel();

  return (
    <div className="quantum-dashboard">
      <div className="quantum-real-time-indicator"></div>
      
      <div className="quantum-command-center">
        <div className="quantum-header">
          <div className="quantum-title">🚀 ZEIN SECURITY WAF v5.0</div>
          <div className="quantum-subtitle">QUANTUM AI CYBER COMMAND CENTER | MULTIDIMENSIONAL THREAT PROTECTION</div>
        </div>
        
        <div className="quantum-system-status">
          {['QUANTUM AI ENGINE: ONLINE', 'NEURAL NETWORK: OPTIMIZED', 'QUANTUM INTELLIGENCE: SYNCED', 'ML THREAT HUNTER: QUANTUM', 'DECEPTION TECH: AI_ENHANCED', 'QUANTUM SHIELD: ACTIVE'].map((status, index) => (
            <div key={index} className="quantum-status-item">
              <span className="quantum-status-indicator quantum-status-online"></span>
              {status}
            </div>
          ))}
        </div>
        
        <div className="quantum-tab-container">
          <div className="quantum-tab-buttons">
            {[
              { id: 'quantum_dashboard', label: 'QUANTUM DASHBOARD' },
              { id: 'quantum_threats', label: 'QUANTUM THREATS' },
              { id: 'quantum_attackers', label: 'ATTACKER ANALYSIS' },
              { id: 'quantum_ai', label: 'QUANTUM AI COMMAND' }
            ].map(tab => (
              <button
                key={tab.id}
                className={`quantum-tab-button ${activeTab === tab.id ? 'active' : ''}`}
                onClick={() => setActiveTab(tab.id)}
              >
                {tab.label}
              </button>
            ))}
          </div>
          
          <div className="quantum-tab-content">
            {activeTab === 'quantum_dashboard' && (
              <div className="dashboard-grid">
                <div className="quantum-panel">
                  <div className="panel-title">📊 QUANTUM SECURITY METRICS</div>
                  <div className="quantum-stats-grid">
                    <StatCard value={stats.total_requests} label="Quantum Requests" type="ai" />
                    <StatCard value={stats.blocked_requests} label="Threats Neutralized" type="critical" />
                    <StatCard value={stats.sql_injections} label="SQL Injection Attacks" type="high" />
                    <StatCard value={stats.xss_attempts} label="XSS Attempts" type="high" />
                    <StatCard value={stats.brute_force} label="Brute Force Attacks" type="medium" />
                    <StatCard value={stats.zero_day_attempts} label="Zero-Day Exploits" type="critical" />
                    <StatCard value={`${stats.block_rate?.toFixed(2)}%`} label="Quantum Block Rate" type="quantum" />
                    <StatCard value={stats.threat_actors} label="Tracked Threat Actors" type="high" />
                  </div>
                </div>
                
                <div className="quantum-panel">
                  <div className="panel-title">🌍 QUANTUM THREAT MAP</div>
                  <div className="quantum-map-container">
                    <div className="map-placeholder">
                      <div className="map-icon">⚛️</div>
                      <div>Quantum Threat Visualization</div>
                      <div className="map-subtitle">Tracking attackers in quantum space</div>
                    </div>
                    {[...Array(15)].map((_, i) => (
                      <div 
                        key={i}
                        className="quantum-map-point"
                        style={{
                          top: `${Math.random() * 80 + 10}%`,
                          left: `${Math.random() * 80 + 10}%`
                        }}
                      />
                    ))}
                  </div>
                </div>
                
                <div className="quantum-panel">
                  <div className="panel-title">📈 QUANTUM SECURITY LOGS</div>
                  <div className="quantum-logs-container">
                    {logs.length > 0 ? (
                      logs.map((log, index) => (
                        <div key={log.id || index} className={`quantum-log-entry quantum-log-severity-${log.Severity?.toLowerCase()}`}>
                          <div className="quantum-log-time">
                            {new Date(log.Timestamp).toLocaleString()}
                          </div>
                          <div>
                            <span className="quantum-log-ip">{log.IP}</span> - 
                            <span className="quantum-log-type"> {log.AttackType}</span> - 
                            <span style={{ color: getSeverityColor(log.Severity) }}> {log.Severity}</span>
                          </div>
                          <div className="quantum-log-details">
                            {log.Method} {log.Path} | Quantum Score: {log.ThreatScore?.toFixed(2)} | {log.Description}
                          </div>
                        </div>
                      ))
                    ) : (
                      <div className="no-logs">No security logs available</div>
                    )}
                  </div>
                </div>
                
                <div className="quantum-panel">
                  <div className="panel-title">⚡ QUANTUM AI SYSTEMS</div>
                  <div className="quantum-stats-grid">
                    <StatCard value="98.50%" label="Quantum Detection" type="quantum" />
                    <StatCard value="12" label="Dark Web Threats" type="high" />
                    <StatCard value="8" label="Quantum Traps" type="medium" />
                    <StatCard value={stats.threat_actors} label="AI Decisions" type="ai" />
                  </div>
                  <div className={`quantum-threat-level ${threatLevel.class}`}>
                    QUANTUM THREAT LEVEL: {threatLevel.level}
                  </div>
                </div>
              </div>
            )}
            
            {activeTab === 'quantum_ai' && (
              <div className="quantum-panel">
                <div className="panel-title">🤖 QUANTUM AI COMMAND INTERFACE</div>
                <div className="quantum-ai-console" ref={consoleRef}>
                  {aiConsole.map((entry, index) => (
                    <div key={index} className="quantum-command-line">
                      <span className={`quantum-command-prompt ${entry.type}`}>
                        {entry.type === 'user' ? 'QUANTUM_USER>' : 'QUANTUM_AI>'}
                      </span>
                      {entry.message}
                    </div>
                  ))}
                </div>
                <div className="quantum-ai-commands">
                  {[
                    'QUANTUM_DEFENSE',
                    'AI_OPTIMIZATION', 
                    'THREAT_ANALYSIS',
                    'QUANTUM_SCAN',
                    'NEURAL_ENHANCE',
                    'SHIELD_BOOST'
                  ].map(command => (
                    <button
                      key={command}
                      className="quantum-ai-command-btn"
                      onClick={() => executeQuantumAICommand(command)}
                    >
                      {command.replace('_', ' ')}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ value, label, type }) => (
  <div className="quantum-stat-card">
    <div className={`quantum-stat-value ${type}`}>{value}</div>
    <div className="quantum-stat-label">{label}</div>
  </div>
);

const getSeverityColor = (severity) => {
  const colors = {
    'CRITICAL': '#ff4444',
    'HIGH': '#ff6b00', 
    'MEDIUM': '#ffff00',
    'LOW': '#00ff41'
  };
  return colors[severity] || '#00ff41';
};

export default QuantumDashboard;
